import React from 'react';
import { useState, useEffect } from 'react';

function BookForm() {
  const [query, setQuery] = useState("");
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);

  // Logica di ricerca su OpenLibrary
  useEffect(() => {
    console.log("funzione ricerca chiamata");
    if (query.trim().length < 2) {
      setResults([]);
      return;
    }

    const timer = setTimeout(async () => {
      setLoading(true);
      const res = await fetch(
        `http://localhost:3000/openlibrary/search?q=${encodeURIComponent(query)}`
      );
      const data = await res.json();
      setResults(data);
      setLoading(false);
    }, 500);

    return () => clearTimeout(timer);
  }, [query]);

  return (
    <div className="book-form-container">
      <h2>Aggiungi un Nuovo Libro</h2>
      <form className="book-form">
        <div className="form-group">
          <label htmlFor="title">Titolo</label>
          <input
            type="text"
            id="title"
            name="title"
            placeholder="Inserisci il titolo..."
            value={query}
            onChange={(e)=> setQuery(e.target.value)}
          />
        </div>
        <button type="submit" className="submit-btn" onClick="useEffect">Aggiungi Libro</button>
      </form>
      <ul>
        {results.map((book) => (
          <li key={book.openLibraryKey}>
            {book.title} — {book.author} ({book.year})
          </li>
        ))}
      </ul>
    </div>
  );
};

export default BookForm;
